import { describe, expect, it } from 'vitest';

import {
  THOTH_NEARBY_BUSINESSES_CAP,
  fetchThothNearbyBusinesses,
  isThothNearbyBusinessesMetrics,
  renderThothNearbyBusinessesPromptContext,
  resolveThothNearbyBusinesses,
  thothNearbyBusinessesFromPlaces,
  thothNearbyBusinessesFromPoiElements,
  type SovereignPoiElement,
} from '../src/thoth-nearby-businesses';

const OBSERVER = { lat: 44.9, lon: -86.0 };

function poi(
  name: string,
  lat: number,
  lon: number,
  tags: Record<string, unknown> = {},
): SovereignPoiElement {
  return { type: 'node', id: Math.round(lat * 1e6), lat, lon, tags: { name, ...tags } };
}

describe('Thoth nearby-businesses sense of place', () => {
  it('assembles metrics from Overpass-shaped POI elements with distance and bearing', () => {
    const metrics = thothNearbyBusinessesFromPoiElements(
      [
        poi('Glen Cafe', 44.901, -86.0, { amenity: 'cafe' }),
        poi('Harbor Books', 44.9, -85.995, { shop: 'books' }),
        // way with center{} instead of lat/lon — still usable.
        {
          type: 'way',
          id: 7,
          center: { lat: 44.899, lon: -86.001 },
          tags: { name: 'Old Mill Inn', tourism: 'hotel' },
        },
        // unnamed element — a sense of place names what it sees; skipped.
        { type: 'node', id: 9, lat: 44.9, lon: -86.0, tags: { amenity: 'bench' } },
      ],
      { observer: OBSERVER, cityName: 'Glen Arbor' },
    );

    expect(metrics).not.toBeNull();
    expect(isThothNearbyBusinessesMetrics(metrics)).toBe(true);
    expect(metrics!.cityName).toBe('Glen Arbor');
    expect(metrics!.source).toBe('sovereign-osm');
    expect(metrics!.nonAuthoritative).toBe(true);
    expect(metrics!.businessCount).toBe(3);
    // Nearest first; every entry carries a rounded distance and an 8-wind bearing.
    expect(metrics!.businesses[0]!.name).toBe('Glen Cafe');
    expect(metrics!.businesses[0]!.bearing).toBe('N');
    expect(metrics!.businesses[0]!.distanceMeters).toBeGreaterThan(80);
    expect(metrics!.businesses[0]!.distanceMeters).toBeLessThan(140);
    for (const b of metrics!.businesses) {
      expect(typeof b.distanceMeters).toBe('number');
      expect(typeof b.bearing).toBe('string');
    }
    // OSM tag precedence read.
    expect(metrics!.businesses.find((b) => b.name === 'Harbor Books')!.category).toBe('books');
  });

  it('orders deterministically (distance asc, then name) and caps the entry count', () => {
    const many: SovereignPoiElement[] = [];
    for (let i = 0; i < 30; i++) {
      many.push(poi(`Shop ${String(i).padStart(2, '0')}`, 44.9 + i * 0.0005, -86.0, { shop: 'gift' }));
    }
    // Two same-distance entries — name breaks the tie.
    many.push(poi('Aardvark Annex', 44.9 - 0.0005, -86.0, { shop: 'gift' }));

    const shuffled = [...many].reverse();
    const a = thothNearbyBusinessesFromPoiElements(many, { observer: OBSERVER });
    const b = thothNearbyBusinessesFromPoiElements(shuffled, { observer: OBSERVER });

    expect(a!.businesses.length).toBe(THOTH_NEARBY_BUSINESSES_CAP);
    expect(a!.businesses).toEqual(b!.businesses);
    // Same distance as 'Shop 01': alphabetical tie-break puts Aardvark first.
    const names = a!.businesses.map((e) => e.name);
    expect(names.indexOf('Aardvark Annex')).toBeLessThan(names.indexOf('Shop 01'));
  });

  it('degrades to an absent modality (null) on empty, unnamed-only, or malformed input', () => {
    expect(thothNearbyBusinessesFromPoiElements([], { observer: OBSERVER })).toBeNull();
    expect(thothNearbyBusinessesFromPoiElements(null, { observer: OBSERVER })).toBeNull();
    expect(
      thothNearbyBusinessesFromPoiElements(
        [{ type: 'node', id: 1, lat: 44.9, lon: -86.0, tags: { amenity: 'bench' } }],
        { observer: OBSERVER },
      ),
    ).toBeNull();
    expect(thothNearbyBusinessesFromPlaces([], { observer: OBSERVER })).toBeNull();
  });

  it('builds from knotgraph places and works without an observer (name-ordered, no distances)', () => {
    const metrics = thothNearbyBusinessesFromPlaces([
      { name: 'Zest Deli', category: 'food-drink', lat: 44.9, lon: -86.0 },
      { name: 'Anchor Outfitters', category: 'retail', lat: 44.91, lon: -86.01 },
    ]);
    expect(metrics).not.toBeNull();
    expect(metrics!.source).toBe('sovereign-places');
    expect(metrics!.observerLat).toBeNull();
    expect(metrics!.businesses.map((b) => b.name)).toEqual(['Anchor Outfitters', 'Zest Deli']);
    expect(metrics!.businesses[0]!.distanceMeters).toBeUndefined();
  });

  it('fetches from the sovereign POI endpoint and never throws on failure', async () => {
    const seen: string[] = [];
    const okFetch = (async (url: unknown) => {
      seen.push(String(url));
      return {
        ok: true,
        json: async () => ({
          elements: [poi('Glen Cafe', 44.901, -86.0, { amenity: 'cafe' })],
        }),
      };
    }) as unknown as typeof fetch;

    const metrics = await fetchThothNearbyBusinesses({
      ...OBSERVER,
      cityName: 'Glen Arbor',
      fetchImpl: okFetch,
    });
    expect(metrics).not.toBeNull();
    expect(metrics!.businesses[0]!.name).toBe('Glen Cafe');
    expect(seen[0]).toContain('/api/osm/poi?bbox=');

    // Network failure → absent modality, no throw.
    const downFetch = (async () => {
      throw new Error('network down');
    }) as unknown as typeof fetch;
    expect(await fetchThothNearbyBusinesses({ ...OBSERVER, fetchImpl: downFetch })).toBeNull();

    // Non-OK status → absent modality.
    const errFetch = (async () => ({ ok: false, json: async () => ({}) })) as unknown as typeof fetch;
    expect(await fetchThothNearbyBusinesses({ ...OBSERVER, fetchImpl: errFetch })).toBeNull();
  });

  it('falls back to the knotgraph places endpoint when the POI leg is empty and a cityKey exists', async () => {
    const seen: string[] = [];
    const fallbackFetch = (async (url: unknown) => {
      const u = String(url);
      seen.push(u);
      if (u.includes('/api/osm/poi')) {
        return { ok: true, json: async () => ({ elements: [] }) };
      }
      return {
        ok: true,
        json: async () => ({
          places: [{ name: 'Zest Deli', category: 'food-drink', lat: 44.9, lon: -86.0 }],
        }),
      };
    }) as unknown as typeof fetch;

    const metrics = await fetchThothNearbyBusinesses({
      ...OBSERVER,
      cityKey: 'glen-arbor-mi',
      fetchImpl: fallbackFetch,
    });
    expect(metrics).not.toBeNull();
    expect(metrics!.source).toBe('sovereign-places');
    expect(seen.some((u) => u.includes('/api/places/glen-arbor-mi'))).toBe(true);
  });

  it('resolves request extensions: passthrough metrics, observer fetch, or honest absence', async () => {
    const prebuilt = thothNearbyBusinessesFromPlaces([
      { name: 'Zest Deli', category: 'food-drink', lat: 44.9, lon: -86.0 },
    ])!;
    expect(await resolveThothNearbyBusinesses({ thoth_nearby_businesses: prebuilt })).toBe(
      prebuilt,
    );

    // No observer at all → absent, no fetch attempted.
    expect(await resolveThothNearbyBusinesses({})).toBeNull();
    expect(
      await resolveThothNearbyBusinesses({ thoth_observer: { lat: 'x', lon: -86 } }),
    ).toBeNull();

    // Observer present → sourced from the sovereign endpoint.
    const okFetch = (async () => ({
      ok: true,
      json: async () => ({
        elements: [poi('Glen Cafe', 44.901, -86.0, { amenity: 'cafe' })],
      }),
    })) as unknown as typeof fetch;
    const resolved = await resolveThothNearbyBusinesses(
      { thoth_observer: { lat: OBSERVER.lat, lon: OBSERVER.lon, city_name: 'Glen Arbor' } },
      { fetchImpl: okFetch },
    );
    expect(resolved).not.toBeNull();
    expect(resolved!.cityName).toBe('Glen Arbor');
  });

  it('renders a compact prompt context in the established kv-line shape', () => {
    const metrics = thothNearbyBusinessesFromPoiElements(
      [poi('Glen Cafe', 44.901, -86.0, { amenity: 'cafe' })],
      { observer: OBSERVER, cityName: 'Glen Arbor' },
    )!;
    const prompt = renderThothNearbyBusinessesPromptContext(metrics);
    expect(prompt).toContain('kind=thoth.nearby-businesses.v1');
    expect(prompt).toContain('city=Glen_Arbor');
    expect(prompt).toContain('source=sovereign-osm');
    expect(prompt).toContain('nonAuthority=true');
    expect(prompt).toContain('businessCount=1');
    expect(prompt).toMatch(/business\.1=Glen_Cafe_\(cafe,_~\d+m_N\)/);
  });
});
